sys_ui_page.client_script:
initPage();

// Use this function to initialize variables at page load
function initPage() {
	// set a default radio button as selected
	gel('taskOnly').checked = true;
	gel('tasksByDate').disabled = gel('closedAt').value == '';
}

// dialog_button id="cancel" was clicked, user does not want to reopen the task
function onCancel() {
	// below will auto close popup
	GlideDialogWindow.get().destroy();
	return false;
}

// dialog_button id="submit" was clicked, user confirms wanting to reopen the task
function onSubmit() {

	return true;
}

sys_ui_page.description:
New UI Page to prompt from Platform about re-opening completed or cancelled tasks
2.8.0 | 2022-04-12 | mmcc | STRY0113587 - Mass Reopen Task Modal- Update Labels for UX In <g:messages> Removed Tasker - This Task and all Subtasks closed on or after Add Tasker - This Task and {0} Subtasks closed with this task on {1} Added <g:evaluate var="jvar_messageOpenTasksCount" jelly="true"> In 3rd row, replace ${gs.getMessage(...)} ${jvar_closedAt} with ${jvar_messageOpenTasksCount}
2.7.0 | 2021-09-14 | mmcc | STRY0099532 - DIA- 'Mass Reopen' Task Tree Modal (MVP) Created UI Page for Reopen Tasks. <input> id="tasksByDate" get disabled when closed_at is empty for selected task. Button id="submit" gets enabled after clicking a radio button. Updated styleSheets array to use tasker-modal-prompt-UIPages. Changed CSS Selector .dtech-perm-delete to use .dtech-standard-text-color. Changed sub-tasks to subtask. 2.7.0 | 2021-10-7 | mmcc | STRY0099532 - DIA- 'Mass Reopen' Task Tree Modal (MVP) Updated to meet new requirements for Messages; added id's to input label's to show msgBody[line# from AC]. 2.7.0 | 2021-10-7 | mmcc | STRY0111802 - Reopen - Radio Button selected by Default Radio button with id="taskOnly" set as default, Submit button always enabled.

sys_ui_page.processing_script:
reopenTasks();

function reopenTasks() {
    var grSelectedTask = new GlideRecord("x_153465_discovert_route_task_instance");
    grSelectedTask.addQuery('sys_id', sysid); //comes from hidden input tag name attribute
    grSelectedTask.query();
    if (grSelectedTask.next()) {
        // Calls a Server function
        new Task_uiAction().uiAction_ReopenTasks(grSelectedTask, reopenType); //comes from radio input tag name attribute
    }

	response.sendRedirect("/x_153465_discovert_route_task_instance.do?sys_id=" + sysid);
}
